+      return;
+    }
+
+    bool expanded;
+    if (n->is_LoadFlat()) {
+      expanded = n->as_LoadFlat()->expand_non_atomic(igvn);
+    } else {
+      expanded = n->as_StoreFlat()->expand_non_atomic(igvn);
+    }
+    if (expanded) {
+      sfn_worklist.remove(n->as_SafePoint());
+      igvn.C->remove_flat_access(n);
+    }
+  });
+  igvn.set_delay_transform(delay);
