+        tty->print("=== At SafePoint node %d can't find value of array element [%d]", sfpt->_idx, elem_idx);
+        tty->print(", which prevents elimination of: ");
+        alloc->dump();
+      }
+#endif // PRODUCT
+    }
+    if (elem_val == nullptr) {
+      return false;
+    }
